-- ============================================
-- XOR ШИФРАТОР ДЛЯ main.lua
-- ============================================

local function encrypt(data, key)
    local encrypted = ""
    for i = 1, #data do
        local char = data:sub(i, i)
        local code = string.byte(char) ~ string.byte(key:sub((i - 1) % #key + 1, (i - 1) % #key + 1))
        encrypted = encrypted .. string.char(code)
    end
    return encrypted
end

